return [
  {
    json: {
      test_name: "Primary Fast LLM",
      prompt: "Respond with exactly the word 'ONLINE'.",
      model_preference: "fast",
      system_message: "You are a validation tester. Be brief."
    }
  },
  {
    json: {
      test_name: "Failover / Large Context LLM",
      prompt: "Respond with exactly the word 'ONLINE'.",
      model_preference: "large-context",
      system_message: "You are a validation tester. Be brief."
    }
  },
  {
    json: {
      test_name: "Hugging Face Embedding",
      prompt: "Verify embedding matrix generation latency and dimension payload.",
      model_preference: "embedding"
    }
  }
];

const items = $input.all();
const summary = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  // Match back to the original test inputs via paired item context
  const originalTest = $('Generate Test Cases').all()[i]?.json || {};

  let status = "🟢 PASS";
  let notes = "Model responded successfully.";

  if (item.error || !item.response || (typeof item.response === 'string' && item.response.startsWith("ERROR:"))) {
    status = "🔴 FAIL";
    notes = item.error?.message || item.response || "Unknown API or Network error.";
  }

  summary.push({
    json: {
      test_name: originalTest.test_name,
      model_preference: originalTest.model_preference,
      model_used: item.model_used || (originalTest.model_preference === 'embedding' ? 'all-MiniLM-L6-v2' : 'Unknown'),
      status: status,
      latency: item.latency_ms ? `${item.latency_ms}ms` : 'N/A',
      tokens_used: item.tokens_input ? (item.tokens_input + item.tokens_output) : 0,
      response_sample: typeof item.response === 'object' ? `Vector Array (Length: ${item.response.length || 0})` : String(item.response).substring(0, 60),
      error_details: notes
    }
  });
}

return summary;
